+
+/// Filter float64 buffer, returns count of matching indices
+export fn filterFloat64Buffer(
+    data_ptr: [*]const f64,
+    len: usize,
+    op: u32,
+    value: f64,
+    out_indices: [*]u32,
+    max_indices: usize,
+) usize {
