+            2 => v < value,
+            3 => v <= value,
+            4 => v > value,
+            5 => v >= value,
+            else => false,
+        };
+        if (matches) {
+            out_indices[out_count] = @intCast(i);
+            out_count += 1;
+        }
+    }
+    return out_count;
